// Fallback to "Valued Customer" if response is null or empty`}],tb=[{title:"Global Error Handler",desc:"Every flow has an implicit error handler. When an unhandled exception occurs (data action timeout, expression error, system failure), the flow jumps to the error handling path. Configure this to play an apology message and transfer to a catch-all queue rather than disconnecting.",steps:['Set up a dedicated "Error Handling" task',`Play: "We're experiencing a technical issue. Let me connect you with an agent."`,'Transfer to ACD: "General_Fallback" queue with no skill requirements',"Log error details to participant attributes for debugging"]},{title:"Data Action Retry Pattern",desc:"External APIs can fail intermittently. Build a retry loop that attempts the data action up to 3 times before falling back to a default behavior.",steps:["Set Flow.RetryCount = 0","Loop: While Flow.RetryCount < 3","Call Data Action → On Success: break out of loop","On Failure: Flow.RetryCount = Flow.RetryCount + 1, wait 2 seconds","After loop: If still failed → use cached/default data and continue"]},{title:"Graceful Degradation",desc:"When a CRM lookup fails, don't block the entire flow. Fall back to a generic experience — the caller still gets helped, just without personalization.",steps:["Call Data Action: CRM Lookup by ANI","On Success: Set Flow.CustomerName, Flow.AccountTier, personalize greeting",'On Failure: Set Flow.CustomerName = "Valued Customer", Flow.AccountTier = "Standard"',"Continue flow with whatever data is available — never let a failed lookup prevent routing"]},{title:"Timeout Escalation",desc:"If a flow step takes too long (e.g., waiting for caller input), escalate rather than looping forever.",steps:["Collect Input with 10-second timeout",`On timeout: play "I didn't receive any input"`,"Retry up to 2 times (3 attempts total)",'After 3 failed attempts: Transfer to ACD with a note "Customer unable to navigate IVR"']}],sb=[{category:"Flow Design",tip:"Keep flows under 200 actions. Break complex logic into Common Modules.",impact:"High"},{category:"Flow Design",tip:"Place the most common decision branches FIRST in Switch actions to minimize evaluation steps.",impact:"Medium"},{category:"Data Actions",tip:"Minimize data action calls — each one adds network latency (typically 200-500ms). Cache results in variables.",impact:"High"},{category:"Data Actions",tip:"Set appropriate timeouts. Default 12 seconds is long for a caller waiting in an IVR. Consider 5-8 seconds.",impact:"High"},{category:"Data Actions",tip:"Batch multiple lookups into a single API call when possible, rather than making separate calls.",impact:"Medium"},{category:"Variables",tip:"Use task-scoped variables for temporary data to reduce memory footprint during execution.",impact:"Low"},{category:"Variables",tip:"Avoid storing large JSON objects in flow variables — extract only the fields you need.",impact:"Medium"},{category:"Expressions",tip:"Pre-compute complex expressions into variables rather than repeating the same expression in multiple actions.",impact:"Medium"},{category:"Audio",tip:"Use pre-recorded audio instead of TTS for frequently played prompts — faster playback and better quality.",impact:"Medium"},{category:"Modules",tip:"Common Modules are loaded once and cached. Moving shared logic into modules reduces per-flow complexity.",impact:"High"}],nb=[{method:"GET",path:"/api/v2/flows",use:"List all Architect flows with type, name, version, and publish status"},{method:"POST",path:"/api/v2/flows",use:"Create a new flow (requires flow definition JSON)"},{method:"GET",path:"/api/v2/flows/{flowId}",use:"Get a specific flow's metadata and configuration"},{method:"GET",path:"/api/v2/flows/{flowId}/latestconfiguration",use:"Download the full flow definition (compiled JSON/YAML)"},{method:"POST",path:"/api/v2/flows/actions/publish",use:"Publish a flow version to make it live"},{method:"POST",path:"/api/v2/flows/actions/checkin",use:"Check in a flow (unlock for other editors)"},{method:"POST",path:"/api/v2/flows/actions/checkout",use:"Check out a flow (lock for editing)"},{method:"GET",path:"/api/v2/flows/{flowId}/versions",use:"List all versions of a flow with timestamps and authors"},{method:"GET",path:"/api/v2/flows/datatables",use:"List all Architect data tables (lookup tables used in flows)"},{method:"POST",path:"/api/v2/flows/datatables/{datatableId}/rows",use:"Add or query rows in an Architect data table"},{method:"GET",path:"/api/v2/flows/milestones",use:"List flow milestones (named checkpoints for analytics)"},{method:"GET",path:"/api/v2/flows/outcomes",use:"List flow outcomes for tracking success/failure metrics"}],ob=[["Flows per org","1,000","Across all flow types"],["Actions per flow","500","Total actions in a single flow"],["Tasks per flow","250","Named task blocks within a flow"],["Variables per flow","250","Flow-scoped variables"],["Variables per task","50","Task-scoped variables"],["Expression length","5,000 chars","Maximum characters in a single expression"],["Menu choices per menu","12","DTMF keys 0-9, *, #"],["Nesting depth (tasks)","25","Call Task within Call Task depth limit"],["Common modules per org","200","Reusable flow modules"],["Data table rows","10,000","Per Architect data table"],["Data table columns","20","Per Architect data table"],["Data tables per org","200","Lookup tables"],["Audio prompts per org","5,000","Pre-recorded prompt files"],["Prompt file size","50 MB","Maximum per audio file"],["TTS character limit","10,000","Characters per TTS action"],["Data action timeout (sync)","12 seconds","Default; configurable up to 60s"],["Data action timeout (async)","60 seconds","For workflow-type flows"],["Flow publish history","200 versions","Per flow; oldest versions pruned"],["Concurrent flow executions","Unlimited","Platform scales automatically"],["Bot intents per flow","250","Maximum intents in a bot flow"],["Bot utterances per intent","250","Training phrases per intent"],["Slots per intent","25","Variables captured per intent"]],ib=[["Architect Inbound Call Flows",!0,!0,!0],["Architect Inbound Chat/Email Flows",!0,!0,!0],["Architect Inbound Message Flows","add-on",!0,!0],["Common Modules",!0,!0,!0],["In-Queue Flows",!0,!0,!0],["Outbound Call Flows",!0,!0,!0],["Workflow (event-triggered)",!0,!0,!0],["Data Actions (Web Services)",!0,!0,!0],["Architect Data Tables",!0,!0,!0],["Text-to-Speech (TTS)",!0,!0,!0],["Bot Flows (Genesys Dialog Engine)",!1,!0,!0],["Digital Bot Flows",!1,!0,!0],["Secure Call Flows (PCI)","add-on","add-on",!0],["Third-party NLU integration",!1,!1,!0],["Advanced speech recognition (ASR)",!1,"add-on",!0],["Flow milestones & outcomes analytics",!0,!0,!0]],rb=[{symptom:"Flow not executing — calls go to default handling",investigation:"Check: Is the flow PUBLISHED? (Draft flows do not execute.) Is the correct flow assigned to the phone number/DID? (Admin > Telephony > Call Routing) Is the flow in the correct Division? (Check division assignments in Admin > People & Permissions > Divisions) Does the user have the correct permissions to view the flow binding? Check flow publish status via the Architect UI or GET /api/v2/flows/{flowId}."},{symptom:"Data Action returning errors in the flow",investigation:"Check: Test the data action OUTSIDE the flow first (Admin > Integrations > Actions > Test). Verify the input contract matches what the flow is sending (type mismatches are common). Check the external API endpoint — is it accessible from Genesys Cloud? (Firewall rules, IP whitelisting) Review the timeout setting — is the API slower than the configured timeout? Check authentication credentials (OAuth token expired? API key rotated?)."},{symptom:"Schedule evaluation returning wrong state",investigation:"Check: Verify the timezone on the schedule — is it set to the correct IANA timezone? Are holiday schedules overriding the regular schedule? (Holidays take precedence.) Is an Emergency Toggle active? (Admin > Contact Center > Emergency Groups) Check for overlapping schedule blocks within the same schedule group. Use Architect Debug mode to step through the Evaluate Schedule Group action and inspect the output."},{symptom:"Variables losing values or returning null",investigation:"Check: Is the variable initialized before use? (Unset variables return NOT_SET, not null.) Are you mixing task-scoped and flow-scoped variables? (Task variables are cleared when the task ends.) Is a data action failure path being taken without setting fallback values? Check expression syntax — type mismatches (comparing String to Integer) cause silent failures. Use the Architect Debugger to inspect variable values at each step."},{symptom:"Bot flow not recognizing customer intents",investigation:`Check: Does each intent have at least 10-15 training utterances? Are utterances varied enough? (Avoid minor variations of the same phrase.) Are slots configured with the correct entity types? Check the NLU confidence threshold — too high causes frequent "I didn't understand" responses (default: 0.4 is a good start). Re-train the NLU model after adding new intents or utterances. Use the NLU testing tool to evaluate recognition accuracy before publishing.`},{symptom:"Flow execution time is too long (slow IVR)",investigation:"Check: How many data action calls does the flow make? Each adds 200-500ms+ of latency. Are there redundant loops or deeply nested task calls? Is TTS being generated for every prompt? (Pre-recorded audio is faster.) Check for expression complexity — very long expressions with many function calls slow evaluation. Review the flow action count — flows approaching 500 actions may hit performance ceilings. Consider breaking into Common Modules for better caching."}],ab=(()=>{const a=[];return Wx.forEach(t=>a.push({text:t.title,label:t.title,sectionId:t.id,tier:t.tier,type:"Section"})),Jl.forEach(t=>{const l=hm[t.id]||{};a.push({text:`${t.label} ${t.sub} ${l.explanation||""} ${l.analogy||""}`,label:t.label,sectionId:"t1s2",tier:0,type:"Component"})}),_x.forEach(t=>a.push({text:`${t.name} ${t.desc}`,label:t.name,sectionId:"t1s3",tier:0,type:"Flow Type"})),Tu.forEach(t=>a.push({text:`${t.title} ${t.desc} ${(t.checks||[]).join(" ")}`,label:t.title,sectionId:"t1s4",tier:0,type:"Lifecycle Step"})),Hx.forEach(t=>a.push({text:`${t.term} ${t.def}`,label:t.term,sectionId:"t1s5",tier:0,type:"Glossary"})),Vx.forEach(t=>a.push({text:`${t.title} ${t.detail}`,label:t.title,sectionId:"t2s1",tier:1,type:"Prerequisite"})),Bl.forEach(t=>a.push({text:`${t.action} ${t.desc} ${t.category}`,label:t.action,sectionId:"t2s2",tier:1,type:"Action"})),Yx.forEach(t=>a.push({text:`${t[0]} ${t[1]}`,label:t[0],sectionId:"t2s3",tier:1,type:"Config Option"})),Qx.forEach(t=>a.push({text:`${t.category} ${t.expr} ${t.desc}`,label:`${t.category}: ${t.expr.substring(0,40)}`,sectionId:"t2s4",tier:1,type:"Expression"})),Kx.forEach(t=>a.push({text:`${t[0]} ${t[1]} ${t[2]}`,label:t[0],sectionId:"t2s5",tier:1,type:"Comparison"})),Jx.forEach(t=>a.push({text:`${t.name} ${t.desc}`,label:t.name,sectionId:"t2s6",tier:1,type:"Bot Concept"})),Nu.forEach(t=>a.push({text:`Step ${t.step} ${t.text}`,label:`Secure Step ${t.step}`,sectionId:"t2s7",tier:1,type:"Secure Flow"})),Xx.forEach(t=>a.push({text:`${t.title} ${t.desc}`,label:t.title,sectionId:"t2s8",tier:1,type:"Debug Tip"})),Zx.forEach(t=>a.push({text:t,label:t.substring(0,50),sectionId:"t3s1",tier:2,type:"Runtime Step"})),eb.forEach(t=>a.push({text:`${t.title} ${t.code}`,label:t.title,sectionId:"t3s2",tier:2,type:"Expression"})),tb.forEach(t=>a.push({text:`${t.title} ${t.desc} ${t.steps.join(" ")}`,label:t.title,sectionId:"t3s3",tier:2,type:"Error Pattern"})),sb.forEach(t=>a.push({text:`${t.category} ${t.tip} ${t.impact}`,label:`${t.category}: ${t.tip.substring(0,40)}`,sectionId:"t3s4",tier:2,type:"Performance Tip"})),nb.forEach(t=>a.push({text:`${t.method} ${t.path} ${t.use}`,label:`${t.method} ${t.path}`,sectionId:"t3s5",tier:2,type:"API"})),ob.forEach(t=>a.push({text:`${t[0]} ${t[1]} ${t[2]}`,label:t[0],sectionId:"t3s6",tier:2,type:"Limit"})),ib.forEach(t=>a.push({text:`${t[0]} GC1:${t[1]} GC2:${t[2]} GC3:${t[3]}`,label:t[0],sectionId:"t3s7",tier:2,type:"License Feature"})),rb.forEach(t=>a.push({text:`${t.symptom} ${t.investigation}`,label:t.symptom,sectionId:"t3s8",tier:2,type:"Troubleshooting"})),a})(),ok=()=>e.jsx("style",{children:"@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500;600;700&display=swap');"}),ik=({isDark:a})=>e.jsx("style",{children:`
